input.command:
cat << 'EOF' > /etc/nginx/sites-available/default
server {
    listen 8080;
    listen [::]:8080;

    server_name _;

    root /web/server;
    index index.html;

    location / {
        try_files $uri $uri/ =404;
    }
}
EOF
nginx -t && service nginx restart

